# -----------------------------------------------------------------------------
# Geometry helpers
# -----------------------------------------------------------------------------

def assign_material(obj, material):
    if material is not None:
        obj.data.materials.append(material)
    return obj


def add_box(name, location, dimensions, material, collection="DETAILS",
            rotation=(0.0, 0.0, 0.0), bevel=0.0):
    bpy.ops.mesh.primitive_cube_add(location=location, rotation=rotation)
    obj = bpy.context.object
    obj.name = name
    obj.dimensions = dimensions
    bpy.ops.object.transform_apply(location=False, rotation=False, scale=True)
    assign_material(obj, material)
    move_to_collection(obj, collection)
    if bevel > 0:
        modifier = obj.modifiers.new(name="Softly worn edges", type='BEVEL')
        modifier.width = bevel
        modifier.segments = 2
    return obj


def add_mesh(name, vertices, faces, materials, collection="DETAILS", material_indices=None):
    mesh = bpy.data.meshes.new(f"{name}_mesh")
    mesh.from_pydata(vertices, [], faces)
    mesh.update()
    obj = bpy.data.objects.new(name, mesh)
    move_to_collection(obj, collection)
    for mat in materials:
        mesh.materials.append(mat)
    if material_indices:
        for poly, idx in zip(mesh.polygons, material_indices):
            poly.material_index = idx
            poly.use_smooth = False
    else:
        for poly in mesh.polygons:
            poly.use_smooth = False
    return obj


def cylinder_between(name, p1, p2, radius, material, collection="DETAILS",
                     vertices=8, bevel=0.0):
    p1 = Vector(p1)
    p2 = Vector(p2)
    delta = p2 - p1
    length = delta.length
    midpoint = (p1 + p2) * 0.5
    bpy.ops.mesh.primitive_cylinder_add(vertices=vertices, radius=radius, depth=length, location=midpoint)
    obj = bpy.context.object
    obj.name = name
    obj.rotation_mode = 'QUATERNION'
    obj.rotation_quaternion = delta.to_track_quat('Z', 'Y')
    assign_material(obj, material)
    move_to_collection(obj, collection)
    if bevel > 0:
        modifier = obj.modifiers.new(name="Edge wear", type='BEVEL')
        modifier.width = bevel
        modifier.segments = 1
    return obj


def square_beam_between(name, p1, p2, thickness, depth, material,
                        collection="DETAILS", bevel=0.025):
    p1 = Vector(p1)
    p2 = Vector(p2)
    delta = p2 - p1
    obj = add_box(
        name, (p1 + p2) * 0.5, (thickness, depth, delta.length),
        material, collection, bevel=bevel
    )
    obj.rotation_mode = 'QUATERNION'
    obj.rotation_quaternion = delta.to_track_quat('Z', 'Y')
    return obj


def ground_z(x, y):
    z = -0.15 + 0.008 * y
    z += 0.20 * math.sin(x * 0.42 + 0.5) * math.cos(y * 0.31)
    z += 0.075 * math.sin(y * 0.83 - x * 0.21)
    # Flatten the building clearing while retaining a softly rolling perimeter.
    dx = max(abs(x - 1.5) - 5.4, 0.0)
    dy = max(abs(y - 0.7) - 5.8, 0.0)
    blend = min(1.0, math.sqrt(dx * dx + dy * dy) / 3.0)
    return z * blend


def add_ico_rock(name, location, scale, material=None, collection="DETAILS", seed=0):
    local = random.Random(seed)
    bpy.ops.mesh.primitive_ico_sphere_add(subdivisions=1, radius=1.0, location=location)
    obj = bpy.context.object
    obj.name = name
    obj.scale = (
        scale[0] * local.uniform(0.82, 1.18),
        scale[1] * local.uniform(0.82, 1.18),
        scale[2] * local.uniform(0.82, 1.18),
    )
    obj.rotation_euler = Euler((local.random(), local.random(), local.random()))
    assign_material(obj, material or STONE[seed % len(STONE)])
    move_to_collection(obj, collection)
    return obj


def add_point_light(name, location, color, energy, radius=0.45):
    data = bpy.data.lights.new(name=f"{name}_data", type='POINT')
    data.color = color
    data.energy = energy
    data.shadow_soft_size = radius
    obj = bpy.data.objects.new(name, data)
    obj.location = location
    move_to_collection(obj, "LIGHTS")
    return obj


def add_area_light(name, location, color, energy, size, target):
    data = bpy.data.lights.new(name=f"{name}_data", type='AREA')
    data.color = color
    data.energy = energy
    data.shape = 'DISK'
    data.size = size
    obj = bpy.data.objects.new(name, data)
    obj.location = location
    obj.rotation_euler = (Vector(target) - obj.location).to_track_quat('-Z', 'Y').to_euler()
    move_to_collection(obj, "LIGHTS")
    return obj


