def create_terrain():
    nx, ny = 27, 29
    xmin, xmax = -18.0, 18.0
    ymin, ymax = -14.0, 23.0
    verts = []
    for j in range(ny + 1):
        y = ymin + (ymax - ymin) * j / ny
        for i in range(nx + 1):
            x = xmin + (xmax - xmin) * i / nx
            # Edge-safe XY jitter creates organic triangular facets.
            jx = 0 if i in (0, nx) else rng.uniform(-0.22, 0.22)
            jy = 0 if j in (0, ny) else rng.uniform(-0.22, 0.22)
            xx, yy = x + jx, y + jy
            verts.append((xx, yy, ground_z(xx, yy)))
    faces = []
    indices = []
    for j in range(ny):
        for i in range(nx):
            a = j * (nx + 1) + i
            b = a + 1
            d = (j + 1) * (nx + 1) + i
            c = d + 1
            if (i + j) % 2:
                faces.extend(((a, b, d), (b, c, d)))
            else:
                faces.extend(((a, b, c), (a, c, d)))
            # Sunward side trends slightly lighter; deterministic micro-variation.
            base_idx = rng.choices(range(len(GROUND)), weights=(28, 27, 18, 16, 11), k=2)
            indices.extend(base_idx)
    return add_mesh("Faceted moss clearing", verts, faces, GROUND, "TERRAIN", indices)


def create_path():
    centers = [
        (-1.5, -13.1), (-1.8, -11.8), (-2.1, -10.5), (-2.3, -9.2),
        (-2.4, -7.8), (-2.0, -6.7), (-1.2, -5.7), (-0.3, -4.8),
        (0.4, -4.0), (1.2, -3.25), (1.25, -2.65)
    ]
    widths = [2.4, 2.25, 2.1, 1.95, 2.0, 1.85, 1.85, 1.7, 1.65, 1.55, 1.5]
    left, right = [], []
    for i, (x, y) in enumerate(centers):
        if i == 0:
            tangent = Vector((centers[1][0] - x, centers[1][1] - y))
        elif i == len(centers) - 1:
            tangent = Vector((x - centers[i - 1][0], y - centers[i - 1][1]))
        else:
            tangent = Vector((centers[i + 1][0] - centers[i - 1][0], centers[i + 1][1] - centers[i - 1][1]))
        tangent.normalize()
        normal = Vector((-tangent.y, tangent.x))
        width = widths[i] * 0.5
        edge_jitter = rng.uniform(-0.12, 0.12)
        lx, ly = x + normal.x * (width + edge_jitter), y + normal.y * (width + edge_jitter)
        rx, ry = x - normal.x * (width - edge_jitter), y - normal.y * (width - edge_jitter)
        left.append((lx, ly, ground_z(lx, ly) + 0.045))
        right.append((rx, ry, ground_z(rx, ry) + 0.048))
    verts = []
    for l, r in zip(left, right):
        verts.extend((l, r))
    faces, indices = [], []
    for i in range(len(centers) - 1):
        a, b, c, d = 2 * i, 2 * i + 1, 2 * i + 3, 2 * i + 2
        if i % 2:
            faces.extend(((a, b, d), (b, c, d)))
        else:
            faces.extend(((a, b, c), (a, c, d)))
        indices.extend((rng.randrange(len(PATH_MATS)), rng.randrange(len(PATH_MATS))))
    obj = add_mesh("Winding polygon path", verts, faces, PATH_MATS, "TERRAIN", indices)
    return obj


create_terrain()
create_path()

