def create_mountain(name, location, scale, mat, seed):
    local = random.Random(seed)
    bpy.ops.mesh.primitive_ico_sphere_add(subdivisions=2, radius=1.0, location=location)
    obj = bpy.context.object
    obj.name = name
    obj.scale = scale
    obj.rotation_euler.z = local.uniform(-0.35, 0.35)
    assign_material(obj, mat)
    base_index = MOUNTAIN_MATS.index(mat)
    lighter = MOUNTAIN_MATS[min(base_index + 1, len(MOUNTAIN_MATS) - 1)]
    if lighter != mat:
        obj.data.materials.append(lighter)
    move_to_collection(obj, "BACKGROUND")
    for poly in obj.data.polygons:
        poly.use_smooth = False
        if len(obj.data.materials) > 1 and local.random() < 0.32:
            poly.material_index = 1
    return obj


