CX = 1.5
XMIN, XMAX = -1.5, 4.5
YFRONT, YBACK = -0.55, 4.45
WALL_BASE, EAVE_Z, RIDGE_Z = 0.82, 4.15, 7.25


def create_foundation():
    block_w = 0.83
    # Front and side courses. Individual blocks sell the stylized masonry.
    for row in range(2):
        z = 0.26 + row * 0.34
        offset = (row % 2) * block_w * 0.42
        x = XMIN - 0.25 + offset
        while x < XMAX + 0.25:
            w = min(block_w + rng.uniform(-0.08, 0.08), XMAX + 0.35 - x)
            add_box(
                f"Front foundation block {row}", (x + w * 0.5, YFRONT + 0.02, z),
                (w - 0.035, 0.48, 0.31), rng.choice(STONE), "CABIN",
                rotation=(0, 0, rng.uniform(-0.018, 0.018)), bevel=0.035
            )
            x += block_w
        y = YFRONT + offset
        while y < YBACK + 0.25:
            w = min(block_w + rng.uniform(-0.08, 0.08), YBACK + 0.35 - y)
            add_box(
                f"Side foundation block {row}", (XMAX + 0.02, y + w * 0.5, z),
                (0.48, w - 0.035, 0.31), rng.choice(STONE), "CABIN",
                rotation=(0, 0, rng.uniform(-0.018, 0.018)), bevel=0.035
            )
            y += block_w


def create_log_walls():
    # Dark inner shells provide deep seams behind the individual log courses.
    add_box("Front wall shadow shell", (CX, YFRONT + 0.12, 2.48), (6.0, 0.32, 3.35), WOOD[3], "CABIN")
    add_box("Right wall shadow shell", (XMAX - 0.12, 1.95, 2.48), (0.32, 5.0, 3.35), WOOD[3], "CABIN")
    add_box("Left wall shell", (XMIN + 0.12, 1.95, 2.48), (0.32, 5.0, 3.35), WOOD[0], "CABIN")
    add_box("Back wall shell", (CX, YBACK - 0.12, 2.48), (6.0, 0.32, 3.35), WOOD[0], "CABIN")

    courses = 10
    course_h = (EAVE_Z - WALL_BASE) / courses
    for row in range(courses):
        z = WALL_BASE + course_h * (row + 0.5)
        h = course_h * 0.88
        y = YFRONT - 0.095 + rng.uniform(-0.018, 0.018)
        # Break each course at visually irregular points; door sits over the shell.
        segments = [(-1.48, 0.23), (0.23, 1.97), (1.97, 4.48)]
        if row >= 8:
            segments = [(-1.48, 1.55), (1.55, 4.48)]
        for si, (xa, xb) in enumerate(segments):
            add_box(
                f"Front log course {row:02d}-{si}", ((xa + xb) / 2, y, z),
                (xb - xa - 0.035, 0.38, h), WOOD[(row + si) % 3], "CABIN",
                rotation=(0, 0, rng.uniform(-0.008, 0.008)), bevel=0.035
            )
        # Visible right wall horizontal courses.
        x = XMAX + 0.095 + rng.uniform(-0.018, 0.018)
        side_segments = [(YFRONT, 0.65), (0.65, 2.10), (2.10, 3.50), (3.50, YBACK)]
        for si, (ya, yb) in enumerate(side_segments):
            add_box(
                f"Right log course {row:02d}-{si}", (x, (ya + yb) / 2, z),
                (0.38, yb - ya - 0.028, h), WOOD[(row + si + 1) % 3], "CABIN",
                rotation=(0, 0, rng.uniform(-0.008, 0.008)), bevel=0.035
            )

    # Alternating protruding log ends at the corners.
    for row in range(courses):
        z = WALL_BASE + course_h * (row + 0.5)
        h = course_h * 0.78
        for x in (XMIN - 0.18, XMAX + 0.18):
            if row % 2 == 0:
                add_box(f"Corner cross log {row}", (x, YFRONT - 0.10, z), (0.42, 0.72, h), WOOD[1], "CABIN", bevel=0.035)
            else:
                add_box(f"Corner end log {row}", (x, YFRONT - 0.10, z), (0.70, 0.40, h), WOOD[2], "CABIN", bevel=0.035)

    # Strong structural front beams.
    add_box("Front tie beam", (CX, YFRONT - 0.31, 4.06), (6.36, 0.30, 0.30), WOOD[2], "CABIN", bevel=0.045)
    add_box("Front lower beam", (CX, YFRONT - 0.30, 1.06), (6.30, 0.27, 0.28), WOOD[2], "CABIN", bevel=0.04)


def create_gable():
    verts = [
        (XMIN, YFRONT - 0.02, EAVE_Z - 0.02),
        (XMAX, YFRONT - 0.02, EAVE_Z - 0.02),
        (CX, YFRONT - 0.02, RIDGE_Z - 0.08),
    ]
    add_mesh("Front gable infill", verts, [(0, 1, 2)], [WOOD[0]], "CABIN")
    # Vertical decorative boards in the gable.
    for x in [CX - 2.15, CX - 1.45, CX - 0.72, CX, CX + 0.72, CX + 1.45, CX + 2.15]:
        available = RIDGE_Z - (abs(x - CX) / 3.0) * (RIDGE_Z - EAVE_Z)
        h = max(0.3, available - EAVE_Z)
        add_box(
            "Gable board", (x, YFRONT - 0.12, EAVE_Z + h * 0.5),
            (0.62, 0.24, h * 0.94), rng.choice(WOOD[:3]), "CABIN", bevel=0.02
        )


