def roof_z(x):
    half_run = 3.62
    return EAVE_Z + (RIDGE_Z - EAVE_Z) * (1.0 - abs(x - CX) / half_run)


def create_roof():
    half_run = 3.62
    rise = RIDGE_Z - EAVE_Z
    pitch = math.atan2(rise, half_run)
    roof_depth = 6.12
    y_center = (YFRONT + YBACK) / 2
    slope_len = math.sqrt(half_run * half_run + rise * rise)

    # Under-roof slabs.
    right_center = (CX + half_run * 0.5, y_center, EAVE_Z + rise * 0.5)
    left_center = (CX - half_run * 0.5, y_center, EAVE_Z + rise * 0.5)
    add_box("Right roof underlay", right_center, (slope_len, roof_depth, 0.18), ROOF_MATS[0], "ROOF", rotation=(0, pitch, 0), bevel=0.035)
    add_box("Left roof underlay", left_center, (slope_len, roof_depth, 0.18), ROOF_MATS[0], "ROOF", rotation=(0, -pitch, 0), bevel=0.035)

    # Large overlapping, staggered shingles on both planes.
    rows = 7
    tile_slope = slope_len / rows * 1.30
    cols = 8
    tile_y = roof_depth / cols * 1.10
    y_start = y_center - roof_depth / 2
    for side in (-1, 1):
        angle = pitch if side == 1 else -pitch
        for row in range(rows):
            t = (row + 0.47) / rows
            run = half_run * (1.0 - t)
            x = CX + side * run
            z = EAVE_Z + rise * t
            # Normal offset keeps tiles cleanly above the underlay.
            x += side * 0.055 * math.sin(pitch)
            z += 0.085 * math.cos(pitch)
            stagger = (0.5 * tile_y if row % 2 else 0.0)
            for col in range(cols + 1):
                y = y_start + (col + 0.5) * roof_depth / cols + stagger
                if y > y_start + roof_depth + 0.15:
                    continue
                jitter_y = rng.uniform(-0.025, 0.025)
                jitter_z = rng.uniform(-0.018, 0.018)
                tile = add_box(
                    f"Roof shingle {side:+d}-{row:02d}-{col:02d}",
                    (x, y + jitter_y, z + jitter_z),
                    (tile_slope, tile_y, 0.075),
                    rng.choice(ROOF_MATS), "ROOF",
                    rotation=(0, angle + rng.uniform(-0.008, 0.008), rng.uniform(-0.005, 0.005)),
                    bevel=0.025
                )

    # Heavy ridge and visible front fascia beams.
    cylinder_between("Roof ridge log", (CX, YFRONT - 0.72, RIDGE_Z + 0.15), (CX, YBACK + 0.70, RIDGE_Z + 0.15), 0.18, WOOD[3], "ROOF", 8, 0.018)
    square_beam_between("Front roof right fascia", (CX, YFRONT - 0.73, RIDGE_Z + 0.12), (CX + half_run, YFRONT - 0.73, EAVE_Z - 0.02), 0.22, 0.26, WOOD[2], "ROOF", 0.03)
    square_beam_between("Front roof left fascia", (CX, YFRONT - 0.73, RIDGE_Z + 0.12), (CX - half_run, YFRONT - 0.73, EAVE_Z - 0.02), 0.22, 0.26, WOOD[2], "ROOF", 0.03)
    cylinder_between("Right eave log", (CX + half_run, YFRONT - 0.76, EAVE_Z - 0.02), (CX + half_run, YBACK + 0.72, EAVE_Z - 0.02), 0.15, WOOD[3], "ROOF", 8, 0.015)
    cylinder_between("Left eave log", (CX - half_run, YFRONT - 0.76, EAVE_Z - 0.02), (CX - half_run, YBACK + 0.72, EAVE_Z - 0.02), 0.15, WOOD[3], "ROOF", 8, 0.015)


def create_chimney():
    chimney_x, chimney_y = 3.05, 2.45
    roof_base = roof_z(chimney_x) + 0.02
    brick_h = 0.38
    brick_w = 0.48
    # Intersect the lowest rows with the roof; no fragile boolean is needed.
    chimney_rows = 6
    for row in range(chimney_rows):
        z = roof_base + row * brick_h * 0.84
        offset = 0.22 if row % 2 else 0.0
        for ix in range(2):
            for iy in range(2):
                x = chimney_x + (ix - 0.5) * 0.48 + (offset if iy == 0 else -offset) * 0.20
                y = chimney_y + (iy - 0.5) * 0.43
                add_box(
                    f"Chimney brick {row}-{ix}-{iy}", (x, y, z),
                    (brick_w - 0.035, 0.40, brick_h * 0.78),
                    STONE[(row + ix + iy) % 3], "ROOF",
                    rotation=(0, 0, rng.uniform(-0.02, 0.02)), bevel=0.035
                )
    top_z = roof_base + chimney_rows * brick_h * 0.84
    add_box("Chimney cap", (chimney_x, chimney_y, top_z + 0.08), (1.28, 1.05, 0.18), STONE[3], "ROOF", bevel=0.045)
    add_box("Chimney dark flue", (chimney_x, chimney_y, top_z + 0.29), (0.42, 0.42, 0.30), LANTERN_METAL, "ROOF", bevel=0.025)


create_foundation()
create_log_walls()
create_gable()
create_door_and_windows()
create_roof()
create_chimney()


