def create_porch():
    deck_y0, deck_y1 = -2.90, -0.55
    deck_z = 0.92
    # Stone porch skirt.
    for x in [XMIN - 0.15 + i * 0.83 for i in range(8)]:
        add_box("Porch stone block", (x, deck_y0 + 0.16, 0.47), (0.76, 0.55, 0.42), rng.choice(STONE), "PORCH", bevel=0.04)
    # Floorboards run front-to-back and vary gently in tone.
    plank_count = 15
    for i in range(plank_count):
        x = XMIN - 0.25 + (6.5 / plank_count) * (i + 0.5)
        add_box(
            f"Porch floor plank {i:02d}", (x, (deck_y0 + deck_y1) / 2, deck_z),
            (6.5 / plank_count - 0.025, deck_y1 - deck_y0, 0.16),
            WOOD[i % 3], "PORCH", rotation=(0, 0, rng.uniform(-0.006, 0.006)), bevel=0.025
        )
    # Three broad steps centered below the door.
    for i in range(3):
        z = 0.17 + i * 0.23
        y = -3.58 + i * 0.36
        depth = 0.52
        add_box(f"Front step {i}", (1.10, y, z), (2.0 - i * 0.05, depth, 0.20), WOOD[1 + i % 2], "PORCH", bevel=0.035)
        for j in range(5):
            add_box("Step board seam", (0.18 + j * 0.46, y - 0.01, z + 0.105), (0.035, depth - 0.04, 0.02), WOOD[3], "PORCH")

    # Railing posts and rails; leave a stair opening around x=1.1.
    posts = [(-1.60, deck_y0), (-1.60, -1.70), (-1.60, -0.65),
             (3.98, deck_y0), (3.98, -1.70), (3.98, -0.65),
             (-0.10, deck_y0), (2.30, deck_y0)]
    for i, (x, y) in enumerate(posts):
        add_box(f"Porch post {i}", (x, y, 1.46), (0.21, 0.21, 1.20), WOOD[2], "PORCH", bevel=0.035)
    # Side rails.
    for x in (-1.60, 3.98):
        for z in (1.25, 1.72):
            add_box("Porch side rail", (x, -1.72, z), (0.16, 2.10, 0.16), WOOD[2], "PORCH", bevel=0.025)
        for y in (-2.47, -1.73, -0.99):
            add_box("Porch side baluster", (x, y, 1.37), (0.12, 0.12, 0.63), WOOD[1], "PORCH", bevel=0.02)
    # Front rails split around steps.
    for xa, xb in ((-1.60, -0.10), (2.30, 3.98)):
        for z in (1.25, 1.72):
            add_box("Porch front rail", ((xa + xb) / 2, deck_y0, z), (xb - xa, 0.16, 0.16), WOOD[2], "PORCH", bevel=0.025)
        for x in (xa + 0.45, xb - 0.45):
            add_box("Porch front baluster", (x, deck_y0, 1.37), (0.12, 0.12, 0.63), WOOD[1], "PORCH", bevel=0.02)


