def create_pine(name, location, height, radius, palette, seed, levels=4, collection="VEGETATION"):
    local = random.Random(seed)
    x, y, z0 = location
    trunk_h = height * 0.40
    bpy.ops.mesh.primitive_cylinder_add(vertices=7, radius=height * 0.038, depth=trunk_h, location=(x, y, z0 + trunk_h * 0.5))
    trunk = bpy.context.object
    trunk.name = f"{name} trunk"
    trunk.rotation_euler.z = local.uniform(-0.15, 0.15)
    assign_material(trunk, TRUNK_LIGHT if local.random() > 0.55 else TRUNK)
    move_to_collection(trunk, collection)
    for level in range(levels):
        t = level / max(levels - 1, 1)
        tier_radius = radius * (1.0 - 0.18 * level)
        tier_depth = height * (0.33 - 0.025 * level)
        center_z = z0 + height * (0.41 + 0.17 * level)
        bpy.ops.mesh.primitive_cone_add(
            vertices=7, radius1=tier_radius, radius2=0.06 * tier_radius,
            depth=tier_depth, location=(x, y, center_z)
        )
        crown = bpy.context.object
        crown.name = f"{name} foliage tier {level}"
        crown.rotation_euler.z = local.uniform(0.0, math.tau)
        assign_material(crown, local.choice(palette))
        move_to_collection(crown, collection)
        for poly in crown.data.polygons:
            poly.use_smooth = False
    return trunk


def create_bush(name, location, scale, seed):
    local = random.Random(seed)
    x, y, z = location
    count = local.randint(4, 7)
    for i in range(count):
        ox = local.uniform(-0.55, 0.55) * scale
        oy = local.uniform(-0.45, 0.45) * scale
        oz = local.uniform(0.18, 0.48) * scale
        bpy.ops.mesh.primitive_ico_sphere_add(subdivisions=1, radius=1.0, location=(x + ox, y + oy, z + oz))
        obj = bpy.context.object
        obj.name = f"{name} lobe {i}"
        obj.scale = (local.uniform(0.45, 0.75) * scale, local.uniform(0.42, 0.70) * scale, local.uniform(0.36, 0.62) * scale)
        obj.rotation_euler = (local.random(), local.random(), local.random())
        assign_material(obj, local.choice(FOLIAGE[1:4]))
        move_to_collection(obj, "VEGETATION")


def create_grass_tuft(name, location, scale, seed):
    local = random.Random(seed)
    x, y, z = location
    verts, faces = [], []
    for i in range(4):
        angle = i * math.pi / 4 + local.uniform(-0.22, 0.22)
        width = 0.12 * scale
        height = local.uniform(0.45, 0.85) * scale
        dx, dy = math.cos(angle) * width, math.sin(angle) * width
        lean_x, lean_y = math.cos(angle) * 0.16 * scale, math.sin(angle) * 0.16 * scale
        base = len(verts)
        verts.extend(((x - dx, y - dy, z), (x + dx, y + dy, z), (x + lean_x, y + lean_y, z + height)))
        faces.append((base, base + 1, base + 2))
    return add_mesh(name, verts, faces, [local.choice(GRASS_MATS)], "DETAILS")


def create_mushroom(name, location, scale, color, seed):
    x, y, z = location
    bpy.ops.mesh.primitive_cylinder_add(vertices=7, radius=0.075 * scale, depth=0.32 * scale, location=(x, y, z + 0.16 * scale))
    stem = bpy.context.object
    stem.name = f"{name} stem"
    assign_material(stem, MUSHROOM_STEM)
    move_to_collection(stem, "DETAILS")
    bpy.ops.mesh.primitive_ico_sphere_add(subdivisions=1, radius=0.22 * scale, location=(x, y, z + 0.37 * scale))
    cap = bpy.context.object
    cap.name = f"{name} cap"
    cap.scale = (1.15, 1.15, 0.48)
    assign_material(cap, color)
    move_to_collection(cap, "DETAILS")


