# -----------------------------------------------------------------------------
# Story props: fence lantern, firewood pile, stump and axe
# -----------------------------------------------------------------------------

def create_split_rail_fence():
    posts = [(-7.0,-7.3), (-6.7,-5.2), (-6.1,-3.25)]
    for i,(x,y) in enumerate(posts):
        z = ground_z(x,y)
        add_box(f"Fence post {i}", (x,y,z+0.92), (0.24,0.24,1.85), WOOD[1], "PROPS", rotation=(0.03,-0.02,rng.uniform(-0.06,0.06)), bevel=0.035)
        add_box(f"Fence cap {i}", (x,y,z+1.87), (0.33,0.33,0.16), WOOD[2], "PROPS", bevel=0.035)
    for i in range(len(posts)-1):
        p1, p2 = posts[i], posts[i+1]
        for zoff in (0.73, 1.30):
            square_beam_between(
                f"Fence rail {i}", (p1[0],p1[1],ground_z(*p1)+zoff),
                (p2[0],p2[1],ground_z(*p2)+zoff+0.05),
                0.16,0.16, WOOD[1], "PROPS", 0.025
            )
    # Short hook and glowing lantern on the foremost post.
    x,y = posts[0]
    z = ground_z(x,y)
    add_box("Fence lantern arm", (x+0.38,y,z+1.72), (0.78,0.10,0.10), WOOD[2], "PROPS", bevel=0.025)
    cylinder_between("Fence lantern chain", (x+0.72,y,z+1.72), (x+0.72,y,z+1.36), 0.022, LANTERN_METAL, "PROPS", 6)
    create_lantern("Path lantern", (x+0.72,y,z+1.12), 0.72, True)


def create_log_with_ends(name, p1, p2, radius, seed):
    local = random.Random(seed)
    side = cylinder_between(name, p1, p2, radius, local.choice(WOOD[:3]), "PROPS", 8, 0.018)
    direction = (Vector(p2)-Vector(p1)).normalized()
    # Thin end caps are separate low-poly cylinders.
    for label, p, sign in (("near",Vector(p1),-1),("far",Vector(p2),1)):
        q1 = p - direction * 0.018
        q2 = p + direction * 0.018
        cylinder_between(f"{name} {label} cut end", q1, q2, radius*0.94, WOOD_END, "PROPS", 8)
    return side


def create_woodpile():
    center_x = 6.8
    base_y = -4.05
    base_z = ground_z(center_x,base_y)+0.26
    rows = [
        (-0.72, 4), (-0.24, 4), (0.24, 3), (0.69, 2)
    ]
    for row,(dz,count) in enumerate(rows):
        z = base_z + row*0.40
        for i in range(count):
            y = base_y + (i-(count-1)/2)*0.43
            length = rng.uniform(1.65,2.05)
            p1 = (center_x-length/2, y, z)
            p2 = (center_x+length/2, y+rng.uniform(-0.04,0.04), z+rng.uniform(-0.025,0.025))
            create_log_with_ends(f"Firewood log {row}-{i}", p1,p2, rng.uniform(0.17,0.21), 1500+row*10+i)
    # Two simple retaining rails.
    for y in (base_y-0.92, base_y+0.92):
        cylinder_between("Woodpile retaining rail", (5.65,y,base_z-0.20),(7.95,y,base_z-0.20),0.08,WOOD[3],"PROPS",8)


def create_stump_and_axe():
    x,y = 4.45,-5.05
    z0 = ground_z(x,y)
    bpy.ops.mesh.primitive_cone_add(vertices=9,radius1=0.72,radius2=0.58,depth=0.92,location=(x,y,z0+0.46))
    stump = bpy.context.object
    stump.name = "Chopping stump"
    assign_material(stump,WOOD[1])
    move_to_collection(stump,"PROPS")
    bpy.ops.mesh.primitive_cylinder_add(vertices=9,radius=0.55,depth=0.045,location=(x,y,z0+0.94))
    cut = bpy.context.object
    cut.name = "Stump cut face"
    assign_material(cut,WOOD_END)
    move_to_collection(cut,"PROPS")
    # Angular roots.
    for i in range(5):
        ang=i*math.tau/5+0.25
        square_beam_between(
            f"Stump root {i}",(x+math.cos(ang)*0.38,y+math.sin(ang)*0.38,z0+0.18),
            (x+math.cos(ang)*0.92,y+math.sin(ang)*0.92,z0+0.06),0.20,0.28,WOOD[0],"PROPS",0.025
        )
    # Axe is embedded in the stump, with its handle leaning clearly into the
    # open foreground so the head does not merge with the porch foundation.
    handle_bottom=(3.18,-6.42,z0+0.12)
    handle_top=(4.30,-5.12,z0+1.02)
    cylinder_between("Axe handle",handle_bottom,handle_top,0.075,WOOD[2],"PROPS",8,0.012)
    hb, ht = Vector(handle_bottom), Vector(handle_top)
    cylinder_between("Axe red collar", hb.lerp(ht,0.86), hb.lerp(ht,0.97), 0.097, MUSHROOM_RED, "PROPS", 8, 0.008)
    # Custom wedge head around the top endpoint.
    hx,hy,hz=handle_top
    verts=[
        (hx-0.16,hy-0.14,hz-0.21),(hx+0.50,hy-0.14,hz-0.09),(hx+0.58,hy-0.14,hz+0.22),(hx-0.16,hy-0.14,hz+0.18),
        (hx-0.16,hy+0.14,hz-0.21),(hx+0.50,hy+0.14,hz-0.09),(hx+0.58,hy+0.14,hz+0.22),(hx-0.16,hy+0.14,hz+0.18),
    ]
    faces=[(0,1,2,3),(4,7,6,5),(0,4,5,1),(1,5,6,2),(2,6,7,3),(4,0,3,7)]
    add_mesh("Axe head",verts,faces,[IRON],"PROPS")


create_split_rail_fence()
create_woodpile()
create_stump_and_axe()


