sun_data.angle = math.radians(8.0)
sun = bpy.data.objects.new("Low golden sun",sun_data)
sun.rotation_euler = Euler((math.radians(28),math.radians(-22),math.radians(-38)))
move_to_collection(sun,"LIGHTS")
add_area_light("Cool forest fill", (11.0,4.0,10.0), (0.20,0.34,0.33), 310, 8.0, (1.0,0.5,2.0))

# Camera deliberately targets left of the cabin to place it right-of-center.
cam_data = bpy.data.cameras.new("Hero Camera data")
cam = bpy.data.objects.new("Hero Camera",cam_data)
cam.location = (22.2,-32.0,15.2)
target = Vector((-0.15,0.45,2.75))
cam.rotation_euler = (target-cam.location).to_track_quat('-Z','Y').to_euler()
cam_data.lens = 55.0
cam_data.sensor_width = 36.0
cam_data.dof.use_dof = True
focus = bpy.data.objects.new("Cabin focus",None)
focus.location = (1.15,-0.35,2.45)
move_to_collection(focus,"CAMERA")
cam_data.dof.focus_object = focus
cam_data.dof.aperture_fstop = 1.8
cam_data.dof.aperture_blades = 7
cam_data.dof.aperture_ratio = 1.0
move_to_collection(cam,"CAMERA")
