# Render and color management.
scene.render.resolution_x = 1600
scene.render.resolution_y = 900
scene.render.resolution_percentage = 100
scene.render.image_settings.file_format = 'PNG'
scene.render.image_settings.color_mode = 'RGBA'
scene.render.film_transparent = False
scene.render.filepath = RENDER_PATH
scene.render.use_file_extension = True
scene.render.image_settings.color_depth = '8'
scene.render.resolution_percentage = 100
scene.render.film_transparent = False
scene.view_settings.look = 'AgX - Medium High Contrast'
scene.view_settings.exposure = 0.20

# Transparent-like atmospheric sheet far behind the scene is avoided: depth is
# created with deliberately desaturated geometry, keeping the scene portable.

# Keep the .blend render path direct and portable. Blender 5's compositor API is
# deliberately not required; the modeled emissive panes and point lights provide
# the warm bloom-like hierarchy in both headless and interactive rendering.
scene.use_nodes = False

# Organize outliner and make every object selectable/visible.
for coll in COLLECTIONS.values():
    coll.hide_render = False
    coll.hide_viewport = False

bpy.ops.wm.save_as_mainfile(filepath=BLEND_PATH)
bpy.ops.render.render(write_still=True)

print(f"Saved Blender scene: {BLEND_PATH}")
print(f"Saved render: {RENDER_PATH}")
